import{_ as e,o as r,c as a,a0 as o}from"./chunks/framework.CSGB4SNl.js";const g=JSON.parse('{"title":"Java 并发与集合核心知识点","description":"","frontmatter":{},"headers":[],"relativePath":"java/concurrency/java-core-knowledge.md","filePath":"java/concurrency/java-core-knowledge.md"}'),n={name:"java/concurrency/java-core-knowledge.md"};function d(s,t,i,l,c,p){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="java-并发与集合核心知识点" tabindex="-1">Java 并发与集合核心知识点 <a class="header-anchor" href="#java-并发与集合核心知识点" aria-label="Permalink to &quot;Java 并发与集合核心知识点&quot;">​</a></h1><h2 id="一、volatile-关键字" tabindex="-1">一、volatile 关键字 <a class="header-anchor" href="#一、volatile-关键字" aria-label="Permalink to &quot;一、volatile 关键字&quot;">​</a></h2><p>volatile 两大核心特性：<strong>可见性</strong> 和 <strong>禁止指令重排序</strong>。</p><p>适用于<strong>一写多读</strong>场景，不适用于多写多读（存在写覆盖问题）。</p><p>volatile 只保证引用对象的可见性，不保证数组中每个元素的可见性，可使用 <code>AtomicIntegerArray</code> 保证。</p><p>volatile 不会失效，只有误用场景：JVM 32 位下读写 long/double 可能非原子性，引用对象未初始化完成时访问也可能失效。</p><p>相比锁机制，volatile 是轻量级方案，无锁竞争、无线程阻塞开销。</p><hr><h2 id="二、synchronized-关键字" tabindex="-1">二、synchronized 关键字 <a class="header-anchor" href="#二、synchronized-关键字" aria-label="Permalink to &quot;二、synchronized 关键字&quot;">​</a></h2><p>synchronized 依赖 JVM 的监视器锁和对象头，对代码块/方法加锁。线程访问时检查标记，进入执行、退出释放锁。</p><p>线程获取锁失败后进入等待队列阻塞，锁释放后被唤醒继续执行。synchronized 会自动处理异常，无需手动释放。</p><p>加锁时会清空工作内存，强制线程从主内存重新读取，实现可见性。</p><hr><h2 id="三、aqs-抽象队列同步器" tabindex="-1">三、AQS 抽象队列同步器 <a class="header-anchor" href="#三、aqs-抽象队列同步器" aria-label="Permalink to &quot;三、AQS 抽象队列同步器&quot;">​</a></h2><p>AQS 是并发框架的基石，为子类提供一套唤醒、等待机制。</p><p>核心包含：<strong>state 资源状态</strong>（子类自定义实现）和 <strong>双向链表 FIFO 同步队列</strong>。</p><p>工作流程：线程 CAS 竞争 state 失败后，封装成 Node 节点加入等待队列挂起；持有资源的线程释放后唤醒队首节点。</p><p>AQS 定义获取、释放的抽象方法，子类实现 <code>tryAcquire</code>、<code>tryRelease</code> 等方法判断资源获取与释放逻辑。</p><p>两种模式：<strong>独占模式</strong>（单一线程持有）和 <strong>共享模式</strong>（N 个线程同时持有），state 值分别代表重入次数和可用资源数。</p><hr><h2 id="四、reentrantlock-可重入锁" tabindex="-1">四、ReentrantLock 可重入锁 <a class="header-anchor" href="#四、reentrantlock-可重入锁" aria-label="Permalink to &quot;四、ReentrantLock 可重入锁&quot;">​</a></h2><p>ReentrantLock 与 synchronized 的区别：synchronized 由 JVM 自动管理锁，ReentrantLock 需手动 lock/unlock；synchronized 适用于简单场景，ReentrantLock 适用于复杂场景。</p><p>JDK 1.5 引入，基于 AQS 实现。</p><p><strong>非公平锁</strong>：获取锁时无需排队，可直接 CAS 抢锁，性能更高（减少唤醒和上下文切换开销）。</p><p><strong>可重入锁</strong>：同一线程可多次获取同一把锁，内部维护重入次数，避免重复排队开销。</p><p>获取时 CAS 修改 state 为 1 表示占有，释放时 state 减 1，归零时唤醒等待队列线程。</p><hr><h2 id="五、cas-比较并交换" tabindex="-1">五、CAS 比较并交换 <a class="header-anchor" href="#五、cas-比较并交换" aria-label="Permalink to &quot;五、CAS 比较并交换&quot;">​</a></h2><p>CAS 是 CPU 级别的原子操作：比较变量当前值与预期值，一致则更新为新值，否则不操作。</p><p>三个操作数：内存地址、预期旧值、新值。</p><p>本质是乐观并发控制，适用于冲突少的场景。冲突时自旋重试，可设置重试次数上限或随机等待时间，超限后降级为重量级锁。</p><p><strong>ABA 问题</strong>：CAS 只比较头尾值，无法感知中间变化。解决方式：加版本号或时间戳（如 MySQL 版本号字段）。</p><p><strong>偏向锁</strong>：线程长期占有锁时，记录线程 ID，后续获取锁直接分配给该线程，减少 CAS 开销。</p><p><strong>总线风暴</strong>：CAS 失败时 LOCK 指令将缓存写入主存并广播，其他线程从主存重新读取，高并发下总线负载激增。</p><hr><h2 id="六、常用集合" tabindex="-1">六、常用集合 <a class="header-anchor" href="#六、常用集合" aria-label="Permalink to &quot;六、常用集合&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>实现类</th><th>特点</th></tr></thead><tbody><tr><td><strong>List</strong></td><td>ArrayList</td><td>随机访问快</td></tr><tr><td></td><td>LinkedList</td><td>双向链表，支持队列操作</td></tr><tr><td><strong>Set</strong></td><td>HashSet</td><td>无序、去重</td></tr><tr><td></td><td>LinkedHashSet</td><td>保持插入顺序</td></tr><tr><td></td><td>TreeSet</td><td>红黑树，排序</td></tr><tr><td><strong>Queue</strong></td><td>PriorityQueue</td><td>优先级队列，按大小出队</td></tr><tr><td><strong>Map</strong></td><td>HashMap</td><td>高性能键值对</td></tr><tr><td></td><td>TreeMap</td><td>红黑树，键排序</td></tr><tr><td></td><td>LinkedHashMap</td><td>保持插入顺序</td></tr><tr><td></td><td>ConcurrentHashMap</td><td>线程安全</td></tr><tr><td></td><td>Hashtable</td><td>线程安全（已淘汰）</td></tr></tbody></table><hr><h2 id="七、异常体系" tabindex="-1">七、异常体系 <a class="header-anchor" href="#七、异常体系" aria-label="Permalink to &quot;七、异常体系&quot;">​</a></h2><p>Java 异常继承结构：<code>Throwable</code> → <code>Error</code> / <code>Exception</code>。</p><p><strong>Error</strong>：程序无法处理的错误（如栈溢出），不应捕获。</p><p><strong>Exception</strong>：程序可处理的异常，分两类：</p><ul><li><strong>编译时异常</strong>（受检异常）：如 IOException、SQLException，编译器强制处理</li><li><strong>运行时异常</strong>（非受检异常）：如 NullPointerException、IndexOutOfBoundsException，可不处理</li></ul><hr><h2 id="八、序列化与反序列化" tabindex="-1">八、序列化与反序列化 <a class="header-anchor" href="#八、序列化与反序列化" aria-label="Permalink to &quot;八、序列化与反序列化&quot;">​</a></h2><p><strong>序列化</strong>：Java 对象转为二进制字节流，存硬盘或网络传输。</p><p><strong>反序列化</strong>：字节流转回 Java 对象。</p><p>实现方式：</p><ol><li>类实现 <code>Serializable</code> 接口</li><li>敏感字段加 <code>transient</code> 关键字，序列化时跳过</li><li>显式定义 <code>serialVersionUID</code>，防止类结构变更后反序列化失败</li></ol>',49)])])}const u=e(n,[["render",d]]);export{g as __pageData,u as default};
